<template>
  <div class="page-bg profile-page"><div class="container profile-layout"><aside class="profile-sidebar"><div class="profile-user"><el-avatar :size="72" :src="user.avatar">{{ (user.nickname||'我')[0] }}</el-avatar><h3>{{ user.nickname }}</h3><p>@{{ user.username }}</p><el-tag size="mini" type="success">{{ user.role==='ADMIN'?'管理员':'普通用户' }}</el-tag></div><el-menu :default-active="activeTab" @select="selectTab"><el-menu-item index="published"><i class="el-icon-collection" /><span>我的发布</span></el-menu-item><el-menu-item index="sent"><i class="el-icon-s-promotion" /><span>我的领养申请</span></el-menu-item><el-menu-item index="received"><i class="el-icon-document-checked" /><span>收到的申请</span></el-menu-item><el-menu-item index="messages"><i class="el-icon-chat-line-round" /><span>聊天消息</span><el-badge v-if="unread" :value="unread" /></el-menu-item><el-menu-item index="profile"><i class="el-icon-setting" /><span>个人信息</span></el-menu-item></el-menu></aside><main class="profile-content"><div class="profile-heading"><div><span class="eyebrow">个人中心</span><h1>{{ tabTitle }}</h1></div><el-button v-if="activeTab==='published'" type="primary" icon="el-icon-plus" @click="$router.push('/publish')">发布宠物</el-button></div>
    <section v-if="activeTab==='published'" v-loading="loading"><el-table :data="published" class="data-table"><el-table-column label="宠物" min-width="220"><template slot-scope="scope"><div class="pet-cell"><img :src="scope.row.coverImage" @error="imageFallback"><div><strong>{{ scope.row.name }}</strong><small>{{ scope.row.breed }}</small></div></div></template></el-table-column><el-table-column label="状态" width="100"><template slot-scope="scope"><el-tag :type="petStatus[scope.row.status].type" size="small">{{ petStatus[scope.row.status].text }}</el-tag></template></el-table-column><el-table-column prop="viewCount" label="浏览" width="80" /><el-table-column prop="createTime" label="发布时间" width="170" /><el-table-column label="操作" width="260"><template slot-scope="scope"><el-button type="text" @click="$router.push(`/publish/${scope.row.id}`)">编辑</el-button><el-button v-if="scope.row.status!=='OFFLINE'" type="text" @click="changeStatus(scope.row,'OFFLINE')">下架</el-button><el-button v-else type="text" @click="changeStatus(scope.row,'AVAILABLE')">重新上架</el-button><el-button type="text" class="danger-text" @click="removePet(scope.row)">删除</el-button></template></el-table-column></el-table><el-empty v-if="!loading&&!published.length" description="你还没有发布宠物信息"><el-button type="primary" @click="$router.push('/publish')">立即发布</el-button></el-empty></section>
    <section v-if="activeTab==='sent'" v-loading="loading"><div v-for="item in sent" :key="item.id" class="application-card"><img :src="item.petCoverImage" @error="imageFallback"><div class="application-main"><div><h3>{{ item.petName }}</h3><el-tag :type="appStatus[item.status].type" size="small">{{ appStatus[item.status].text }}</el-tag></div><p><strong>领养原因：</strong>{{ item.reason }}</p><p><strong>居住条件：</strong>{{ item.livingCondition }}</p><small>提交于 {{ item.createTime }} · 发布人 {{ item.ownerNickname }}</small><el-alert v-if="item.reviewRemark" :title="`审核备注：${item.reviewRemark}`" :type="item.status==='APPROVED'?'success':'warning'" :closable="false" /></div></div><el-empty v-if="!loading&&!sent.length" description="还没有提交过领养申请" /></section>
    <section v-if="activeTab==='received'" v-loading="loading"><div v-for="item in received" :key="item.id" class="application-card"><img :src="item.petCoverImage" @error="imageFallback"><div class="application-main"><div><h3>{{ item.applicantNickname }} 申请领养 {{ item.petName }}</h3><el-tag :type="appStatus[item.status].type" size="small">{{ appStatus[item.status].text }}</el-tag></div><p><strong>领养原因：</strong>{{ item.reason }}</p><p><strong>居住条件：</strong>{{ item.livingCondition }}</p><p v-if="item.experience"><strong>养宠经验：</strong>{{ item.experience }}</p><small>提交于 {{ item.createTime }}</small><div v-if="item.status==='PENDING'" class="review-actions"><el-button type="success" size="small" @click="review(item,'APPROVED')">通过申请</el-button><el-button type="danger" plain size="small" @click="review(item,'REJECTED')">驳回</el-button></div></div></div><el-empty v-if="!loading&&!received.length" description="暂时没有收到领养申请" /></section>
    <section v-if="activeTab==='messages'" v-loading="loading"><div v-for="item in conversations" :key="`${item.petId}-${item.otherId}`" class="conversation" @click="openConversation(item)"><el-badge :value="item.unreadCount" :hidden="!item.unreadCount"><img :src="item.petCoverImage" @error="imageFallback"></el-badge><div><div><strong>{{ item.senderNickname }}</strong><span>{{ item.createTime }}</span></div><p>关于「{{ item.petName }}」：{{ item.content }}</p></div><i class="el-icon-arrow-right" /></div><el-empty v-if="!loading&&!conversations.length" description="还没有聊天消息" /></section>
    <section v-if="activeTab==='profile'" class="profile-form-card"><el-form ref="profileForm" :model="profileForm" :rules="profileRules" label-position="top"><el-form-item label="个人头像"><div class="avatar-upload-wrap"><el-upload class="avatar-uploader" action="/api/upload" :headers="uploadHeaders" :show-file-list="false" :on-success="avatarUploadSuccess" :before-upload="beforeAvatarUpload"><div class="avatar-upload-preview"><el-avatar :size="82" :src="profileForm.avatar">{{ (profileForm.nickname||'我')[0] }}</el-avatar><span><i class="el-icon-camera" /> 更换头像</span></div></el-upload><p>支持 JPG、PNG、WebP，图片不超过 5MB</p></div></el-form-item><el-form-item label="用户名"><el-input :value="user.username" disabled /></el-form-item><el-form-item label="昵称" prop="nickname"><el-input v-model.trim="profileForm.nickname" maxlength="30" /></el-form-item><el-form-item label="手机号" prop="phone"><el-input v-model.trim="profileForm.phone" maxlength="20" /></el-form-item><el-form-item label="电子邮箱" prop="email"><el-input v-model.trim="profileForm.email" maxlength="80" /></el-form-item><el-button type="primary" :loading="saving" @click="saveProfile">保存个人信息</el-button></el-form></section>
    </main></div><ChatDialog v-if="chatTarget" v-model="chatVisible" :pet="chatTarget.pet" :other-id="chatTarget.otherId" :other-name="chatTarget.name" /></div>
</template>
<script>
import {petApi,adoptionApi,chatApi,userApi} from '../api';import ChatDialog from '../components/ChatDialog.vue';import {petStatus,appStatus,imageFallback} from '../utils/format'
export default {components:{ChatDialog},data(){const user=JSON.parse(localStorage.getItem('pet_user')||'{}');return{user,activeTab:this.$route.query.tab||'published',loading:false,saving:false,published:[],sent:[],received:[],conversations:[],unread:0,chatVisible:false,chatTarget:null,petStatus,appStatus,profileForm:{nickname:user.nickname,phone:user.phone||'',email:user.email||'',avatar:user.avatar||''},profileRules:{nickname:[{required:true,message:'请输入昵称',trigger:'blur'}],phone:[{pattern:/^$|^1[3-9]\d{9}$/,message:'手机号格式不正确',trigger:'blur'}],email:[{type:'email',message:'邮箱格式不正确',trigger:'blur'}]}}},computed:{tabTitle(){return{published:'我的发布',sent:'我的领养申请',received:'收到的领养申请',messages:'聊天消息',profile:'个人信息'}[this.activeTab]},uploadHeaders(){return{Authorization:`Bearer ${localStorage.getItem('pet_token')}`}}},created(){this.load();this.loadUnread()},methods:{imageFallback,beforeAvatarUpload(file){const validType=/^image\/(jpeg|png|webp)$/.test(file.type);const validSize=file.size/1024/1024<5;if(!validType)this.$message.error('头像仅支持 JPG、PNG 或 WebP 格式');else if(!validSize)this.$message.error('头像图片不能超过 5MB');return validType&&validSize},avatarUploadSuccess(res){if(res.code!==200){this.$message.error(res.message||'头像上传失败');return}this.profileForm.avatar=res.data.url;this.$message.success('头像已上传，请保存个人信息')},selectTab(tab){this.activeTab=tab;this.$router.replace({path:'/profile',query:{tab}}).catch(()=>{});this.load()},async load(){this.loading=true;try{if(this.activeTab==='published'){const d=await petApi.list({ownerId:this.user.id,page:1,pageSize:50,status:''});this.published=d.records}else if(this.activeTab==='sent')this.sent=await adoptionApi.sent();else if(this.activeTab==='received')this.received=await adoptionApi.received();else if(this.activeTab==='messages')this.conversations=await chatApi.conversations();else{const d=await userApi.me();this.user=d;this.profileForm={nickname:d.nickname,phone:d.phone||'',email:d.email||'',avatar:d.avatar||''}}}finally{this.loading=false}},async loadUnread(){try{const d=await chatApi.unread();this.unread=d.count}catch(_){ }},async changeStatus(pet,status){await petApi.status(pet.id,status);this.$message.success(status==='OFFLINE'?'已下架':'已重新上架');this.load()},removePet(pet){this.$confirm(`确定删除「${pet.name}」吗？删除后不可恢复。`,'删除确认',{type:'warning'}).then(async()=>{await petApi.remove(pet.id);this.$message.success('已删除');this.load()}).catch(()=>{})},review(item,status){const action=status==='APPROVED'?'通过':'驳回';this.$prompt(`填写${action}备注（可选）`,`${action}领养申请`,{inputPlaceholder:'给申请人的说明',confirmButtonText:`确认${action}`}).then(async({value})=>{await adoptionApi.review(item.id,{status,remark:value||''});this.$message.success(`申请已${action}`);this.load()}).catch(()=>{})},openConversation(item){this.chatTarget={pet:{id:item.petId,name:item.petName,coverImage:item.petCoverImage},otherId:item.otherId,name:item.senderNickname};this.chatVisible=true},saveProfile(){this.$refs.profileForm.validate(async valid=>{if(!valid)return;this.saving=true;try{await userApi.update(this.profileForm);const fresh=await userApi.me();localStorage.setItem('pet_user',JSON.stringify(fresh));this.user=fresh;this.$message.success('个人信息已保存');setTimeout(()=>window.location.reload(),400)}finally{this.saving=false}})}}}
</script>
